SELECT baseline."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption" * baseline.weight) AS "electricity.total.energy_consumption__baseline", sum(upgrade."out.electricity.total.energy_consumption" * baseline.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(baseline."out.electricity.total.energy_consumption", 0) - coalesce(upgrade."out.electricity.total.energy_consumption", 0)) * baseline.weight) AS "electricity.total.energy_consumption__savings", sum(baseline."out.natural_gas.total.energy_consumption" * baseline.weight) AS "natural_gas.total.energy_consumption__baseline", sum(upgrade."out.natural_gas.total.energy_consumption" * baseline.weight) AS "natural_gas.total.energy_consumption__upgrade", sum((coalesce(baseline."out.natural_gas.total.energy_consumption", 0) - coalesce(upgrade."out.natural_gas.total.energy_consumption", 0)) * baseline.weight) AS "natural_gas.total.energy_consumption__savings" FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade ON baseline.bldg_id = upgrade.bldg_id AND upgrade.upgrade = 1 AND upgrade.applicability = true WHERE baseline.applicability = true AND baseline."in.state" = 'WY' GROUP BY 1 ORDER BY 1